			input: security.MarketInput{
				Title:       "",
				Description: "Valid description",
				EndTime:     "2024-12-31T23:59:59Z",
			},
			expectedValid: false,
		},
		{
			name: "Title too long",
			input: security.MarketInput{
				Title:       strings.Repeat("a", 200),
				Description: "Valid description",
				EndTime:     "2024-12-31T23:59:59Z",
			},
			expectedValid: false,
		},
		{
			name: "Description too long",
			input: security.MarketInput{
				Title:       "Valid title",
				Description: strings.Repeat("a", 3000),
				EndTime:     "2024-12-31T23:59:59Z",
			},
			expectedValid: false,
		},
		{
			name: "Valid minimal input",
			input: security.MarketInput{
